    'Perso': 'bg-red-500 text-white',
    'Vinto': 'bg-green-500 text-white',
};

const normalizePhoneNumber = (phone: string | undefined): string => {
    if (!phone) return '';
    let normalized = phone.replace(/[\s-()]/g, '');
    if (normalized.startsWith('+39')) {
        normalized = normalized.substring(3);
    } else if (normalized.startsWith('0039')) {
        normalized = normalized.substring(4);
    }
    return normalized;
};

// --- Flash Alert Form ---
interface FlashAlertFormProps {
    users: User[];
    onSuccess: () => void;
}
const FlashAlertForm: React.FC<FlashAlertFormProps> = ({ users, onSuccess }) => {
    const [selectedUserIds, setSelectedUserIds] = useState<string[]>([]);
    const [title, setTitle] = useState('Avviso Importante');
    const [message, setMessage] = useState('');
    const [isSending, setIsSending] = useState(false);

    const clients = users.filter(u => u.role === 'client');

    const handleSend = async () => {
        if (!message.trim() || selectedUserIds.length === 0) {
            alert("Seleziona almeno un destinatario e scrivi un messaggio.");
            return;
        }
        setIsSending(true);
        try {
            await ApiService.broadcastFlashAlert(selectedUserIds, title, message);
            alert("Avviso inviato correttamente!");
            onSuccess();
        } catch (e) {
            console.error(e);
            alert("Errore nell'invio dell'avviso.");
        } finally {
            setIsSending(false);
        }
    };

    const inputClasses = "mt-1 block w-full px-3 py-2 bg-slate-100 dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm focus:outline-none focus:ring-primary-500 focus:border-primary-500 text-slate-900 dark:text-white";

    return (
        <div className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300 mb-2">Destinatari</label>
                <div className="max-h-40 overflow-y-auto p-3 border border-slate-200 dark:border-slate-700 rounded-md bg-slate-50 dark:bg-slate-900/50 space-y-2">
                    <label className="flex items-center gap-2 cursor-pointer p-1 hover:bg-slate-200 dark:hover:bg-slate-800 rounded">
                        <input 
                            type="checkbox" 
                            checked={selectedUserIds.length === clients.length} 
                            onChange={(e) => setSelectedUserIds(e.target.checked ? clients.map(c => c.id) : [])}
                            className="rounded border-gray-300 text-primary-600 focus:ring-primary-500"
                        />
                        <span className="text-sm font-bold">Seleziona Tutti i Clienti</span>
                    </label>
                    <div className="border-t border-slate-200 dark:border-slate-700 my-2"></div>
                    {clients.map(c => (
                        <label key={c.id} className="flex items-center gap-2 cursor-pointer p-1 hover:bg-slate-200 dark:hover:bg-slate-800 rounded">
                            <input 
                                type="checkbox" 
                                checked={selectedUserIds.includes(c.id)}
                                onChange={(e) => {
                                    if(e.target.checked) setSelectedUserIds([...selectedUserIds, c.id]);
                                    else setSelectedUserIds(selectedUserIds.filter(id => id !== c.id));
                                }}
                                className="rounded border-gray-300 text-primary-600 focus:ring-primary-500"
                            />
                            <span className="text-sm">{c.username}</span>
                        </label>
                    ))}
                </div>
            </div>
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Titolo Avviso</label>
                <input type="text" value={title} onChange={e => setTitle(e.target.value)} className={inputClasses} />
            </div>
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Testo Avviso</label>
                <textarea value={message} onChange={e => setMessage(e.target.value)} rows={4} className={inputClasses} placeholder="Inserisci il messaggio che il cliente dovrà leggere..." />
            </div>
            <div className="pt-4 border-t border-slate-200 dark:border-slate-700 flex justify-end">
                <button 
                    onClick={handleSend} 
                    disabled={isSending || selectedUserIds.length === 0} 
                    className="flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-lg shadow hover:bg-red-700 disabled:opacity-50"
                >
                    {isSending ? <Loader2 size={18} className="animate-spin"/> : <Megaphone size={18}/>}
                    Invia Avviso Flash (Ricarica Obbligatoria)
                </button>
            </div>
        </div>
    );
};

// --- Live View Manager ---
const LiveViewManager: React.FC<{ clients: Client[] }> = ({ clients }) => {
    const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });
    const [groupBy, setGroupBy] = useState<'client' | 'service'>('client');
    const [filterClientId, setFilterClientId] = useState<string>('all');

    const filteredLeads = useMemo(() => {
        let leads: Lead[] = [];
        const clientsToFilter = filterClientId !== 'all' ? clients.filter(c => c.id === filterClientId) : clients;
        clientsToFilter.forEach(client => {
            leads.push(...client.leads.filter(l => l.data?._is_historical !== 'true'));
        });
        const filterStart = dateRange.start;
        const filterEnd = dateRange.end;
        if (filterStart || filterEnd) {
             leads = leads.filter(l => {
                const leadDate = new Date(l.created_at);
                const isAfterStart = filterStart ? leadDate >= filterStart : true;
                const isBeforeEnd = filterEnd ? leadDate <= filterEnd : true;
                return isAfterStart && isBeforeEnd;
             });
        }
        return leads;
    }, [clients, filterClientId, dateRange]);

    return (
        <div>
            <div className="bg-white dark:bg-slate-800 shadow-xl rounded-lg overflow-hidden border border-slate-200 dark:border-slate-700 mb-6">
                <div className="p-4 border-b border-slate-200 dark:border-slate-700">
                    <h3 className="text-xl font-bold text-slate-900 dark:text-white flex items-center">
                        <Activity size={20} className="mr-3 text-primary-500"/>
                        Panoramica Live
                    </h3>
                </div>
                <div className="p-4 space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label htmlFor="client-filter-live" className="block text-sm font-medium text-slate-700 dark:text-gray-300">Filtra per Cliente</label>
                            <select
                                id="client-filter-live"
                                value={filterClientId}
                                onChange={e => setFilterClientId(e.target.value)}
                                className="mt-1 bg-slate-100 dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-md py-2 px-3 text-sm focus:outline-none focus:ring-1 focus:ring-primary-500 w-full"
                            >
                                <option value="all">Tutti i Clienti</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Raggruppa per</label>
                            <div className="mt-1 flex rounded-md shadow-sm">
                                <button
                                    type="button"
                                    onClick={() => setGroupBy('client')}
                                    className={`relative inline-flex items-center px-4 py-2 border text-sm font-medium rounded-l-md focus:z-10 focus:outline-none focus:ring-1 focus:ring-primary-500 transition-colors ${groupBy === 'client' ? 'bg-primary-50 dark:bg-slate-700 text-primary-600 dark:text-white border-primary-300 dark:border-primary-500 z-10' : 'bg-white dark:bg-slate-800 hover:bg-gray-50 dark:hover:bg-slate-700/50 border-gray-300 dark:border-slate-600'}`}
                                >
                                    Cliente
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setGroupBy('service')}
                                    className={`relative -ml-px inline-flex items-center px-4 py-2 border text-sm font-medium rounded-r-md focus:z-10 focus:outline-none focus:ring-1 focus:ring-primary-500 transition-colors ${groupBy === 'service' ? 'bg-primary-50 dark:bg-slate-700 text-primary-600 dark:text-white border-primary-300 dark:border-primary-500 z-10' : 'bg-white dark:bg-slate-800 hover:bg-gray-50 dark:hover:bg-slate-700/50 border-gray-300 dark:border-slate-600'}`}
                                >
                                    Servizio
                                </button>
                            </div>
                        </div>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Filtra per Periodo</label>
                        <div className="mt-1">
                            <DateRangeFilter onDateChange={(range) => setDateRange(range as { start: Date | null; end: Date | null })} />
                        </div>
                    </div>
                </div>
            </div>

            <LiveOverview
                leads={filteredLeads}
                clients={clients}
                groupBy={groupBy}
            />
        </div>
    );
};

// --- AdminDashboard Main Component ---
const AdminDashboard: React.FC = () => {
    const [clients, setClients] = useState<Client[]>([]);
    const [users, setUsers] = useState<User[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isLeadModalOpen, setIsLeadModalOpen] = useState(false);
    const [editingClient, setEditingClient] = useState<Client | null>(null);
    const [isUserModalOpen, setIsUserModalOpen] = useState(false);
    const [editingClientForUser, setEditingClientForUser] = useState<Client | null>(null);
    const [isFlashAlertModalOpen, setIsFlashAlertModalOpen] = useState(false);

    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const activeView = searchParams.get('view') || 'leads';
    const [filterClientId, setFilterClientId] = useState<string>('all');
    const [statusFilter, setStatusFilter] = useState<Lead['status'] | 'all'>('all');
    const [searchQuery, setSearchQuery] = useState('');
    const [dateRange, setDateRange] = useState<{ start: Date | null, end: Date | null }>({ start: null, end: null });
    const [expandedClientId, setExpandedClientId] = useState<string | null>(null);
    const [selectedLead, setSelectedLead] = useState<{lead: Lead, client: Client, historicalLeads: Lead[]} | null>(null);
    const [isLeadDetailModalOpen, setIsLeadDetailModalOpen] = useState(false);
    const [selectedLeadIds, setSelectedLeadIds] = useState<Set<string>>(new Set());
    const [leadsPerPage, setLeadsPerPage] = useState(25);
    const [currentPage, setCurrentPage] = useState(1);
    const headerCheckboxRef = useRef<HTMLInputElement>(null);
    const [editingForm, setEditingForm] = useState<SavedForm | null>(null);
    const formGeneratorRef = useRef<HTMLDivElement>(null);
    const [savedFormsModuleKey, setSavedFormsModuleKey] = useState(Date.now());
    const [revenueDateModalState, setRevenueDateModalState] = useState<{
        isOpen: boolean;
        clientId: string | null;
        leadId: string | null;
        leadCreationDate: string | null;
        updates: Partial<Lead> | null;
    }>({ isOpen: false, clientId: null, leadId: null, leadCreationDate: null, updates: null });


    const fetchData = useCallback(async () => {
        if (!isRefreshing) setIsLoading(true);
        try {
            const clientsData = await ApiService.getClients();
            const usersData = await ApiService.getUsers();
            setClients(clientsData);
            setUsers(usersData);
        } catch (error) {
            console.error("Failed to fetch data:", error);
        } finally {
            if (!isRefreshing) setIsLoading(false);
        }
    }, [isRefreshing]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleRefresh = useCallback(async () => {
        setIsRefreshing(true);
        await fetchData();
        setIsRefreshing(false);
    }, [fetchData]);

    const handleToggleExpand = (clientId: string) => {
        setExpandedClientId(currentId => (currentId === clientId ? null : clientId));
    };

    const handleOpenModal = (client: Client | null = null) => {
        setEditingClient(client);
        setIsModalOpen(true);
    };

    const handleOpenUserModal = (client: Client) => {
        setEditingClientForUser(client);
        setIsUserModalOpen(true);
    };

    const handleToggleStatus = async (userId: string, currentStatus: User['status']) => {
        const newStatus = currentStatus === 'active' ? 'suspended' : 'active';
        try {
            await ApiService.updateUserStatus(userId, newStatus);
            if (newStatus === 'suspended') {
                await ApiService.broadcastForceLogout(userId);
            }
            setUsers(prevUsers => prevUsers.map(u => u.id === userId ? { ...u, status: newStatus } : u));
        } catch (error) {
            console.error("Failed to update user status:", error);
        }
    };

    const handleDeleteClient = async (clientId: string) => {
        if(window.confirm("Sei sicuro di voler eliminare questo cliente? L'azione è irreversibile.")){
            await ApiService.deleteClient(clientId);
            fetchData();
        }
    }

    const filteredLeads = useMemo(() => {
        const allLeads = clients.flatMap(client => client.leads.map(lead => ({ lead, client })));
        let filtered = allLeads.filter(item => item.lead.data?._is_historical !== 'true');
        if (filterClientId !== 'all') filtered = filtered.filter(({ client }) => client.id === filterClientId);
        if (statusFilter !== 'all') filtered = filtered.filter(({ lead }) => lead.status === statusFilter);
        if (searchQuery.trim() !== '') {
            const normalizedQuery = searchQuery.toLowerCase().replace(/\s/g, '');
            filtered = filtered.filter(({ lead, client }) => {
                const clientNameMatch = client.name.toLowerCase().replace(/\s/g, '').includes(normalizedQuery);
                if (clientNameMatch) return true;
                return Object.values(lead.data).some(val => val && String(val).toLowerCase().replace(/\s/g, '').includes(normalizedQuery));
            });
        }
        if (dateRange.start) filtered = filtered.filter(({lead}) => new Date(lead.created_at) >= dateRange.start!);
        if (dateRange.end) filtered = filtered.filter(({lead}) => new Date(lead.created_at) <= dateRange.end!);
        return filtered.sort((a, b) => new Date(b.lead.created_at).getTime() - new Date(a.lead.created_at).getTime());
    }, [clients, filterClientId, searchQuery, dateRange, statusFilter]);

    const paginatedLeads = useMemo(() => {
        const start = (currentPage - 1) * leadsPerPage;
        return filteredLeads.slice(start, start + leadsPerPage);
    }, [filteredLeads, currentPage, leadsPerPage]);

    const totalPages = Math.ceil(filteredLeads.length / leadsPerPage);

    const handleSelectLead = (leadId: string, isSelected: boolean) => {
        setSelectedLeadIds(prev => {
            const newSet = new Set(prev);
            if (isSelected) newSet.add(leadId); else newSet.delete(leadId);
            return newSet;
        });
    };

    const handleSelectAllOnPage = (e: React.ChangeEvent<HTMLInputElement>) => {
        const allVisibleIds = paginatedLeads.map(({ lead }) => lead.id);
        if (e.target.checked) setSelectedLeadIds(prev => new Set([...prev, ...allVisibleIds]));
        else setSelectedLeadIds(prev => { const newSet = new Set(prev); allVisibleIds.forEach(id => newSet.delete(id)); return newSet; });
    };

    if (isLoading) return <div className="text-center p-8">Caricamento...</div>;

    const renderView = () => {
        switch (activeView) {
            case 'live': return <LiveViewManager clients={clients} />;
            case 'clients':
                return (
                    <div>
                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
                            <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Gestione Clienti</h2>
                            <div className="flex flex-col sm:flex-row gap-2 w-full sm:w-auto">
                                <button onClick={() => setIsFlashAlertModalOpen(true)} className="flex items-center bg-red-600 text-white px-4 py-2 rounded-lg shadow hover:bg-red-700 transition-colors justify-center">
                                    <Megaphone size={18} className="mr-2"/>
                                    Invia Avviso Rapido
                                </button>
                                <button onClick={() => handleOpenModal()} className="flex items-center bg-primary-600 text-white px-4 py-2 rounded-lg shadow hover:bg-primary-700 transition-colors justify-center">
                                    <Plus size={18} className="mr-2"/>
                                    Aggiungi Cliente
                                </button>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
                            {clients.map(client => {
                                const user = users.find(u => u.id === client.user_id);
                                return (
                                    <div key={client.id} className={`bg-white dark:bg-slate-800 rounded-lg shadow-lg overflow-hidden transition-all duration-300 border border-slate-200 dark:border-slate-700 ${user?.status === 'suspended' ? 'opacity-60' : ''}`}>
                                        <div className="p-4 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center cursor-pointer relative" onClick={() => handleToggleExpand(client.id)}>
                                            <div>
                                                <h3 className="text-lg font-semibold text-slate-900 dark:text-white">{client.name}</h3>
                                                <p className="text-sm text-gray-500 dark:text-gray-400">{client.leads.filter(l => l.data?._is_historical !== 'true').length} lead totali</p>
                                            </div>
                                            <div className="flex items-center space-x-1">
                                                <button onClick={(e) => {e.stopPropagation(); user && handleToggleStatus(user.id, user.status)}} className={`p-2 rounded-full ${user?.status === 'suspended' ? 'text-green-500 hover:text-green-400' : 'text-yellow-600 hover:text-yellow-500'}`} title={user?.status === 'suspended' ? 'Riattiva Cliente' : 'Blocca & Logout Cliente'}>
                                                    {user?.status === 'suspended' ? <UserCheck size={18} /> : <Ban size={18} />}
                                                </button>
                                                <button onClick={(e) => {e.stopPropagation(); handleOpenUserModal(client)}} className="p-2 text-gray-500 dark:text-gray-400 hover:text-primary-500 dark:hover:text-primary-400 rounded-full" title="Gestisci Account"><UserCog size={18} /></button>
                                                <button onClick={(e) => {e.stopPropagation(); handleOpenModal(client)}} className="p-2 text-gray-500 dark:text-gray-400 hover:text-primary-500 dark:hover:text-primary-400 rounded-full" title="Modifica Cliente"><Edit size={18} /></button>
                                                <button onClick={(e) => {e.stopPropagation(); handleDeleteClient(client.id)}} className="p-2 text-gray-500 dark:text-gray-400 hover:text-red-500 rounded-full" title="Elimina Cliente"><Trash2 size={18} /></button>
                                                <span className="p-2 text-gray-500 dark:text-gray-400">{expandedClientId === client.id ? <ChevronUp size={20} /> : <ChevronDown size={20} />}</span>
                                            </div>
                                            {user?.status === 'suspended' && <div className="absolute top-2 left-2 bg-yellow-500 text-white text-xs font-bold px-2 py-1 rounded-full shadow">SOSPESO</div>}
                                        </div>
                                        {expandedClientId === client.id && (
                                             <div className="p-4 bg-slate-50 dark:bg-slate-800/50 space-y-4 text-sm">
                                                <p>Username: <span className="font-mono">{user?.username}</span></p>
                                                <p>Email: <span className="font-mono">{user?.email || 'N/D'}</span></p>
                                             </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                );
            case 'spese': return <AdSpendManager clients={clients} onDataUpdate={fetchData} />;
            case 'forms': return <div className="space-y-12"><FormGenerator clients={clients} onFormSaved={() => setSavedFormsModuleKey(Date.now())} /><SavedFormsModule key={savedFormsModuleKey} clients={clients} onEditForm={(f) => { setEditingForm(f); navigate('/admin/dashboard?view=forms'); }} /></div>;
            case 'leads':
            default:
                return (
                     <div className="bg-white dark:bg-slate-800 shadow-xl rounded-lg overflow-hidden border border-slate-200 dark:border-slate-700">
                        <div className="p-4 border-b border-slate-200 dark:border-slate-700 flex flex-col gap-4">
                            <div className="flex flex-col md:flex-row justify-between md:items-center flex-wrap gap-4">
                                <h3 className="text-xl font-bold text-slate-900 dark:text-white">Tutti i Lead</h3>
                                <div className="flex items-center space-x-2">
                                    <button onClick={() => setIsLeadModalOpen(true)} className="flex items-center bg-primary-600 text-white px-4 py-2 rounded-lg shadow hover:bg-primary-700 transition-colors">
                                        <Plus size={16} className="mr-2"/>
                                        Aggiungi Lead
                                    </button>
                                </div>
                            </div>
                            <div className="flex flex-col md:flex-row items-center gap-4 flex-wrap">
                                <div className="relative w-full md:w-auto">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400 pointer-events-none" />
                                    <input type="text" placeholder="Cerca in tutti i campi..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="bg-slate-100 dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-md py-2 pl-10 pr-3 text-sm focus:outline-none focus:ring-1 focus:ring-primary-500 w-full sm:w-64" />
                                </div>
                                <DateRangeFilter onDateChange={setDateRange} />
                            </div>
                        </div>
                        <div className="overflow-x-auto">
