                                </thead>
                                <tbody className="bg-white dark:bg-slate-900">
                                    {paginatedLeads.map(({ lead, client }) => (
                                        <tr key={lead.id} className="hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                            <td className="px-4 py-4 w-12"><input type="checkbox" checked={selectedLeadIds.has(lead.id)} onChange={(e) => handleSelectLead(lead.id, e.target.checked)} /></td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm font-semibold text-slate-900 dark:text-white">{lead.data.nome || 'N/D'}</td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-gray-300">{client.name}</td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-gray-300">{new Date(lead.created_at).toLocaleDateString('it-IT')}</td>
                                            <td className="px-6 py-4 whitespace-nowrap text-right">
                                                <button onClick={() => { setSelectedLead({lead, client, historicalLeads: []}); setIsLeadDetailModalOpen(true); }} className="text-gray-400 hover:text-primary-500 p-2"><Activity size={16}/></button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                        <div className="p-4 border-t border-slate-200 dark:border-slate-700 flex justify-between items-center">
                            <div className="text-sm text-gray-500">Mostra {paginatedLeads.length} di {filteredLeads.length} lead</div>
                            <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
                        </div>
                    </div>
                );
        }
    };

    return (
        <div>
            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingClient ? 'Modifica Cliente' : 'Nuovo Cliente'}>
                <ClientForm client={editingClient} onSuccess={() => { setIsModalOpen(false); fetchData(); }} />
            </Modal>
            <Modal isOpen={isFlashAlertModalOpen} onClose={() => setIsFlashAlertModalOpen(false)} title="Invia Avviso Flash (Pop-up)">
                <FlashAlertForm users={users} onSuccess={() => setIsFlashAlertModalOpen(false)} />
            </Modal>
            {renderView()}
        </div>
    );
};

