const ProtectedRoute: React.FC<{ children: React.ReactElement; role: 'admin' | 'client' }> = ({ children, role }) => {
    const { user } = useAuth();
    const location = useLocation();

    if (!user) {
        return <Navigate to="/login" state={{ from: location }} replace />;
    }

    if (user.role !== role) {
        const defaultPath = user.role === 'admin' ? '/admin/dashboard' : `/client/${user.id}/dashboard`;
        return <Navigate to={defaultPath} replace />;
    }

    return children;
};

const AppLayout: React.FC<{ role: 'admin' | 'client' }> = ({ role }) => (
    <ProtectedRoute role={role}>
        <Layout>
            <Outlet />
        </Layout>
    </ProtectedRoute>
);

const AppRoutes: React.FC = () => {
    const { user, isLoading, logout } = useAuth();
    const [flashAlert, setFlashAlert] = useState<{title: string, message: string} | null>(null);

    // Listener per il broadcast di force-logout e flash-alert
    useEffect(() => {
        if (!user) return;

        const channel = supabase.channel('platform-events')
            .on('broadcast', { event: 'logout' }, (payload) => {
                if (payload.userId === user.id) {
                    console.log("Sospensione rilevata. Eseguo logout forzato.");
                    logout();
                }
            })
            .on('broadcast', { event: 'flash-alert' }, (payload) => {
                if (payload.userIds.includes(user.id) || payload.userIds.includes('all')) {
                    setFlashAlert({ title: payload.title, message: payload.message });
                }
            })
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user, logout]);

    if (isLoading) {
        return <div className="w-screen h-screen flex items-center justify-center">Caricamento / Loading...</div>;
    }

    const handleFlashAlertOk = () => {
        setFlashAlert(null);
        window.location.reload();
    };

    // This component handles redirection for the root path '/'.
    const RootRedirector: React.FC = () => {
        if (user) {
            const dashboardPath = user.role === 'admin' ? '/admin/dashboard' : `/client/${user.id}/dashboard`;
            return <Navigate to={dashboardPath} replace />;
        }
        return <Navigate to="/login" replace />;
    };

    return (
        <>
            <Routes>
                <Route path="/login" element={<LoginPage />} />
                <Route path="/api/lead/:clientId" element={<ApiHandlerPage />} />

                <Route path="/admin" element={<AppLayout role="admin" />}>
                    <Route path="dashboard" element={<AdminDashboard />} />
                    <Route path="calendar" element={<CalendarPage />} />
                    <Route path="quotes" element={<QuotesPage />} />
                    <Route path="analytics" element={<AnalyticsPage />} />
                    <Route path="revenue" element={<MwsRevenuePage />} />
                    <Route path="settings" element={<AccountSettingsPage />} />
                    <Route path="terms" element={<TermsPage />} />
                    <Route path="chat" element={<ChatPage />} />
                    <Route path="send-notification" element={<SendNotificationPage />} />
                    <Route path="manage-notifications" element={<ManageNotificationsPage />} />
                    <Route path="notifications" element={<NotificationsPage />} />
                    <Route index element={<Navigate to="dashboard" replace />} />
                </Route>

                <Route path="/client/:userId" element={<AppLayout role="client" />}>
                    <Route path="dashboard" element={<ClientDashboard />} />
                    <Route path="calendar" element={<CalendarPage />} />
                    <Route path="quotes" element={<QuotesPage />} />
                    <Route path="analytics" element={<AnalyticsPage />} />
                    <Route path="revenue" element={<MwsRevenuePage />} />
                    <Route path="settings" element={<AccountSettingsPage />} />
                    <Route path="terms" element={<TermsPage />} />
                    <Route path="chat" element={<ChatPage />} />
                    <Route path="notifications" element={<NotificationsPage />} />
                    <Route index element={<Navigate to="dashboard" replace />} />
                </Route>

                <Route path="/" element={<RootRedirector />} />
                <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>

            {/* Modal Avviso Flash Globale */}
            {flashAlert && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border-2 border-primary-500 w-full max-w-md overflow-hidden animate-in zoom-in duration-300">
                        <div className="bg-primary-600 p-4 text-white flex items-center gap-3">
                            <Megaphone className="w-6 h-6 animate-bounce" />
                            <h2 className="text-xl font-bold">{flashAlert.title}</h2>
                        </div>
                        <div className="p-6">
                            <p className="text-slate-700 dark:text-gray-200 text-lg leading-relaxed whitespace-pre-wrap">
                                {flashAlert.message}
                            </p>
                            <div className="mt-8 flex flex-col gap-2">
                                <button 
                                    onClick={handleFlashAlertOk}
                                    className="w-full bg-primary-600 hover:bg-primary-700 text-white font-bold py-4 rounded-xl shadow-lg transition-transform active:scale-95"
                                >
                                    HO CAPITO, AGGIORNA ORA
                                </button>
                                <p className="text-center text-xs text-slate-400 mt-2 italic">
                                    Nota: Cliccando su OK la piattaforma verrà ricaricata per applicare le modifiche.
                                </p>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
};

