const normalizePhoneNumber = (phone: string | undefined): string => {
    if (!phone) return '';
    let normalized = phone.replace(/[\s-()]/g, '');
    if (normalized.startsWith('+39')) {
        normalized = normalized.substring(3);
    } else if (normalized.startsWith('0039')) {
        normalized = normalized.substring(4);
    }
    return normalized;
};

// --- Flash Alert Form ---
interface FlashAlertFormProps {
    users: User[];
    onSuccess: () => void;
}
const FlashAlertForm: React.FC<FlashAlertFormProps> = ({ users, onSuccess }) => {
    const [selectedUserIds, setSelectedUserIds] = useState<string[]>([]);
    const [title, setTitle] = useState('Avviso Importante');
    const [message, setMessage] = useState('');
    const [isSending, setIsSending] = useState(false);

    const clients = users.filter(u => u.role === 'client');

    const handleSend = async () => {
        if (!message.trim() || selectedUserIds.length === 0) {
            alert("Seleziona almeno un destinatario e scrivi un messaggio.");
            return;
        }
        setIsSending(true);
        try {
            await ApiService.broadcastFlashAlert(selectedUserIds, title, message);
            alert("Avviso inviato correttamente!");
            onSuccess();
        } catch (e) {
            console.error(e);
            alert("Errore nell'invio dell'avviso.");
        } finally {
            setIsSending(false);
        }
    };

    const inputClasses = "mt-1 block w-full px-3 py-2 bg-slate-100 dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm focus:outline-none focus:ring-primary-500 focus:border-primary-500 text-slate-900 dark:text-white";

    return (
        <div className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300 mb-2">Destinatari</label>
                <div className="max-h-40 overflow-y-auto p-3 border border-slate-200 dark:border-slate-700 rounded-md bg-slate-50 dark:bg-slate-900/50 space-y-2">
                    <label className="flex items-center gap-2 cursor-pointer p-1 hover:bg-slate-200 dark:hover:bg-slate-800 rounded">
                        <input 
                            type="checkbox" 
                            checked={selectedUserIds.length === clients.length} 
                            onChange={(e) => setSelectedUserIds(e.target.checked ? clients.map(c => c.id) : [])}
                            className="rounded border-gray-300 text-primary-600 focus:ring-primary-500"
                        />
                        <span className="text-sm font-bold">Seleziona Tutti i Clienti</span>
                    </label>
                    <div className="border-t border-slate-200 dark:border-slate-700 my-2"></div>
                    {clients.map(c => (
                        <label key={c.id} className="flex items-center gap-2 cursor-pointer p-1 hover:bg-slate-200 dark:hover:bg-slate-800 rounded">
                            <input 
                                type="checkbox" 
                                checked={selectedUserIds.includes(c.id)}
                                onChange={(e) => {
                                    if(e.target.checked) setSelectedUserIds([...selectedUserIds, c.id]);
                                    else setSelectedUserIds(selectedUserIds.filter(id => id !== c.id));
                                }}
                                className="rounded border-gray-300 text-primary-600 focus:ring-primary-500"
                            />
                            <span className="text-sm">{c.username}</span>
                        </label>
                    ))}
                </div>
            </div>
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Titolo Avviso</label>
                <input type="text" value={title} onChange={e => setTitle(e.target.value)} className={inputClasses} />
            </div>
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Testo Avviso</label>
                <textarea value={message} onChange={e => setMessage(e.target.value)} rows={4} className={inputClasses} placeholder="Inserisci il messaggio che il cliente dovrà leggere..." />
            </div>
            <div className="pt-4 border-t border-slate-200 dark:border-slate-700 flex justify-end">
                <button 
