// FIX: Added missing AdSpendForm component.
interface AdSpendFormProps {
    clients: Client[];
    spend?: AdSpend | null;
    onSuccess: () => void;
    onCancel: () => void;
}

const AdSpendForm: React.FC<AdSpendFormProps> = ({ clients, spend, onSuccess, onCancel }) => {
    const [clientId, setClientId] = useState(spend?.client_id || (clients.length > 0 ? clients[0].id : ''));
    const [service, setService] = useState(spend?.service || '');
    const [platform, setPlatform] = useState<AdSpendPlatform>(spend?.platform || 'Meta');
    const [amount, setAmount] = useState(spend?.amount ? String(spend.amount) : '');
    const [date, setDate] = useState(spend?.date || new Date().toISOString().split('T')[0]);
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState('');

    const selectedClient = clients.find(c => c.id === clientId);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        if (!clientId || !service || !amount || !date) {
            setError("Tutti i campi sono obbligatori.");
            return;
        }

        setIsSaving(true);
        try {
            const data = {
                service,
                platform,
                amount: parseFloat(amount),
                date,
            };
            if (spend) {
                await ApiService.updateAdSpend(clientId, spend.id, data);
            } else {
                await ApiService.addAdSpend(clientId, data);
            }
            onSuccess();
        } catch (err: any) {
            setError(err.message || "Errore durante il salvataggio.");
        } finally {
            setIsSaving(false);
        }
    };

    const inputClasses = "mt-1 block w-full px-3 py-2 bg-slate-100 dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-md shadow-sm focus:outline-none focus:ring-primary-500 focus:border-primary-500 text-slate-900 dark:text-white";

    return (
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Cliente</label>
                <select value={clientId} onChange={e => setClientId(e.target.value)} disabled={!!spend} className={inputClasses}>
                    {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
            </div>
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Servizio</label>
                <select value={service} onChange={e => setService(e.target.value)} className={inputClasses} required>
                    <option value="" disabled>Seleziona un servizio...</option>
                    {selectedClient?.services.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                </select>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Piattaforma</label>
                    <select value={platform} onChange={e => setPlatform(e.target.value as AdSpendPlatform)} className={inputClasses}>
                        <option value="Meta">Meta</option>
                        <option value="Google">Google</option>
                        <option value="TikTok">TikTok</option>
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Importo (€)</label>
                    <input type="number" step="0.01" value={amount} onChange={e => setAmount(e.target.value)} className={inputClasses} placeholder="0.00" required />
                </div>
            </div>
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">Data</label>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className={inputClasses} required />
            </div>
            {error && <p className="text-sm text-red-500">{error}</p>}
            <div className="flex justify-end space-x-3 pt-4 border-t border-slate-200 dark:border-slate-700">
                <button type="button" onClick={onCancel} className="bg-slate-200 dark:bg-slate-600 text-slate-800 dark:text-white px-4 py-2 rounded-lg hover:bg-slate-300 dark:hover:bg-slate-500">Annulla</button>
                <button type="submit" disabled={isSaving} className="bg-primary-600 text-white px-4 py-2 rounded-lg shadow hover:bg-primary-700 disabled:opacity-50">
                    {isSaving ? "Salvataggio..." : "Salva Spesa"}
                </button>
            </div>
        </form>
    );
};

// FIX: Added missing AdSpendManager component.
interface AdSpendManagerProps {
    clients: Client[];
    onDataUpdate: () => void;
}
const AdSpendManager: React.FC<AdSpendManagerProps> = ({ clients, onDataUpdate }) => {
    const [selectedClientId, setSelectedClientId] = useState<string>('all');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingSpend, setEditingSpend] = useState<AdSpend | null>(null);

    const allSpends = useMemo(() => {
        const spends: (AdSpend & { clientName: string })[] = [];
        clients.forEach(client => {
            if (selectedClientId === 'all' || client.id === selectedClientId) {
                (client.adSpends || []).forEach(spend => {
                    spends.push({ ...spend, clientName: client.name });
                });
            }
        });
        return spends.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    }, [clients, selectedClientId]);

    const handleDelete = async (spendId: string) => {
        if (!window.confirm("Sei sicuro di voler eliminare questa spesa?")) return;
        const spend = allSpends.find(s => s.id === spendId);
        if (spend && spend.client_id) {
            try {
                await ApiService.deleteAdSpend(spend.client_id, spendId);
                onDataUpdate();
            } catch (err) {
                console.error(err);
                alert("Errore durante l'eliminazione.");
            }
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Gestione Spese Pubblicitarie</h2>
                <button onClick={() => { setEditingSpend(null); setIsModalOpen(true); }} className="flex items-center bg-primary-600 text-white px-4 py-2 rounded-lg shadow hover:bg-primary-700">
                    <Plus size={18} className="mr-2"/> Aggiungi Spesa
                </button>
            </div>
