            case 'spese': return <AdSpendManager clients={clients} onDataUpdate={fetchData} />;
            case 'forms': return <div className="space-y-12"><FormGenerator clients={clients} onFormSaved={() => setSavedFormsModuleKey(Date.now())} /><SavedFormsModule key={savedFormsModuleKey} clients={clients} onEditForm={(f) => { setEditingForm(f); navigate('/admin/dashboard?view=forms'); }} /></div>;
            case 'leads':
            default:
                return (
                     <div className="bg-white dark:bg-slate-800 shadow-xl rounded-lg overflow-hidden border border-slate-200 dark:border-slate-700">
